mapper.insert:
INSERT INTO code (
    code_id, code_val, code_nm, parnts_code_val, type,
    reg_id, reg_dt, chg_id, chg_dt, del_yn
) VALUES (
    #{codeId}, #{codeVal}, #{codeNm}, #{parntsCodeVal}, #{type},
    #{regId}, #{regDt}, #{chgId}, #{chgDt}, #{delYn}
)

mapper.update:
UPDATE code
SET
    code_nm = #{codeNm},
    parnts_code_val = #{parntsCodeVal},
    type = #{type},
    chg_id = #{chgId},
    chg_dt = #{chgDt}
WHERE code_id = #{codeId}
  AND code_val = #{codeVal}

UPDATE code
SET del_yn = 'Y',
    chg_dt = now()
WHERE code_id = #{codeId}
  AND code_val = #{codeVal}
